"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Intro","href":"/docs/intro","docId":"intro","unlisted":false},{"type":"link","label":"DNS - EDNS","href":"/docs/dns-edns","docId":"dns-edns","unlisted":false},{"type":"link","label":"DNS: UDP vs TCP","href":"/docs/dns-udp-tcp.md","docId":"dns-udp-tcp.md","unlisted":false},{"type":"link","label":"Socket handover","href":"/docs/socket-handover","docId":"socket-handover","unlisted":false},{"type":"link","label":"TCP framing","href":"/docs/tcp-framing","docId":"tcp-framing","unlisted":false},{"type":"link","label":"Wireshark","href":"/docs/wireshark","docId":"wireshark","unlisted":false}]},"docs":{"dns-edns":{"id":"dns-edns","title":"DNS - EDNS","description":"Normally, max size of a UDP DNS message is 512 octets, DNS request is usually smaller than this, but the response may be larger. If the server notices the response exceeds the limit, it will set the truncated bit (TC) to on. When the client receives the response with TC bit ON, it must choose to discard the response or fallback to TCP.","sidebar":"tutorialSidebar"},"dns-udp-tcp.md":{"id":"dns-udp-tcp.md","title":"DNS: UDP vs TCP","description":"Normally, DNS message would be sent over UDP protocols, this is because UDP is much faster than TCP, and that\'s all DNS needs. DNS is not a so important information that should be transfered by TCP.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Intro","description":"This is my site","sidebar":"tutorialSidebar"},"socket-handover":{"id":"socket-handover","title":"Socket handover","description":"There are many ways for a server to handle TCP listening socket, one of them is to handle a established socket with a client to another thread. Today, we will talk about that.","sidebar":"tutorialSidebar"},"tcp-framing":{"id":"tcp-framing","title":"TCP framing","description":"TCP is different from UDP, probably you\'ve heard that TCP is reliable and UDP is not. But what more?","sidebar":"tutorialSidebar"},"wireshark":{"id":"wireshark","title":"Wireshark","description":"Wireshark is a very strong tools for network analysis, let\'s talk about how to use it.","sidebar":"tutorialSidebar"}}}}')}}]);